var BOXES=[["Aries", 10, 31, 1.8, 3.3], ["Taurus", 0, 31, 3.3, 5.9], ["Gemini", 10, 35, 5.9, 8.0], ["Cancer", 7, 33, 8.0, 9.3], ["Leo", -6, 33, 9.3, 11.6], ["Virgo", -22, 14, 11.6, 15.1], ["Libra", -30, 0, 15.1, 16.0], ["Scorpius", -46, -8, 16.0, 17.7], ["Ophiuchus", -30, 14, 16.0, 18.7], ["Sagittarius", -45, -12, 17.7, 20.3], ["Capricornus", -28, -8, 20.3, 21.8], ["Aquarius", -25, 3, 21.8, 23.5], ["Pisces", -7, 33, 23.5, 24], ["Pisces", -7, 33, 0, 1.8], ["Ursa Minor", 66, 90, 0, 24], ["Ursa Major", 28, 73, 8.0, 14.5], ["Draco", 47, 86, 9.3, 21.0], ["Cassiopeia", 46, 77, 22.9, 24], ["Cassiopeia", 46, 77, 0, 3.4], ["Cepheus", 53, 88, 20.0, 24], ["Cepheus", 53, 88, 0, 0.9], ["Camelopardalis", 52, 86, 3.2, 14.5], ["Perseus", 30, 59, 1.5, 4.8], ["Andromeda", 21, 53, 22.9, 24], ["Andromeda", 21, 53, 0, 2.4], ["Auriga", 27, 56, 4.4, 7.5], ["Lynx", 33, 62, 6.2, 9.7], ["Bootes", 7, 55, 13.5, 15.7], ["Corona Borealis", 26, 40, 15.3, 16.4], ["Hercules", 4, 51, 15.8, 18.3], ["Lyra", 25, 48, 18.2, 19.4], ["Cygnus", 27, 61, 19.1, 22.0], ["Lacerta", 35, 57, 21.9, 22.9], ["Pegasus", 2, 36, 21.1, 23.0], ["Pegasus", 2, 36, 23.0, 24], ["Triangulum", 25, 37, 1.8, 2.8], ["Coma Berenices", 14, 34, 11.9, 13.5], ["Canes Venatici", 28, 53, 12.1, 14.1], ["Leo Minor", 23, 42, 9.3, 11.1], ["Delphinus", 2, 21, 20.2, 21.1], ["Sagitta", 16, 21, 18.9, 20.3], ["Vulpecula", 19, 29, 19.0, 21.5], ["Aquila", -12, 19, 18.6, 20.6], ["Equuleus", 2, 13, 20.9, 21.4], ["Orion", -11, 17, 4.7, 6.25], ["Canis Major", -33, -11, 6.1, 7.4], ["Canis Minor", 0, 13, 7.1, 8.2], ["Monoceros", -11, 12, 6.25, 8.1], ["Hydra", -35, 7, 8.1, 15.0], ["Corvus", -25, -11, 11.9, 12.9], ["Crater", -25, -6, 10.8, 11.9], ["Sextans", -12, 7, 9.7, 10.8], ["Cetus", -25, 11, 23.0, 24], ["Cetus", -25, 11, 0, 3.4], ["Eridanus", -58, 1, 1.4, 5.2], ["Serpens", -16, 26, 15.1, 18.7], ["Scutum", -16, -3, 18.2, 18.9], ["Crater", -25, -6, 10.8, 11.9], ["Crux", -65, -55, 11.9, 12.9], ["Centaurus", -65, -29, 11.0, 15.0], ["Lupus", -55, -29, 14.2, 16.1], ["Carina", -75, -50, 6.0, 11.3], ["Vela", -57, -37, 8.0, 11.2], ["Puppis", -51, -11, 6.0, 8.4], ["Pyxis", -37, -17, 8.4, 9.5], ["Antlia", -40, -24, 9.5, 11.1], ["Norma", -60, -42, 15.5, 16.6], ["Ara", -68, -46, 16.6, 18.2], ["Triangulum Australe", -70, -60, 14.9, 17.1], ["Circinus", -71, -55, 13.6, 15.5], ["Musca", -75, -64, 11.3, 13.7], ["Apus", -83, -67, 13.8, 18.2], ["Pavo", -75, -57, 17.7, 21.5], ["Indus", -74, -45, 20.5, 23.5], ["Grus", -57, -37, 21.4, 23.4], ["Phoenix", -58, -39, 23.4, 24], ["Phoenix", -58, -39, 0, 2.4], ["Tucana", -75, -57, 22.1, 24], ["Tucana", -75, -57, 0, 1.5], ["Hydrus", -82, -58, 0, 4.6], ["Reticulum", -67, -53, 3.2, 4.6], ["Horologium", -67, -40, 2.2, 4.3], ["Dorado", -70, -49, 3.9, 6.6], ["Pictor", -64, -43, 4.5, 6.8], ["Caelum", -49, -27, 4.2, 5.1], ["Columba", -43, -27, 5.1, 6.6], ["Lepus", -27, -11, 4.6, 6.2], ["Fornax", -40, -24, 1.8, 3.5], ["Sculptor", -40, -25, 23.1, 24], ["Sculptor", -40, -25, 0, 1.8], ["Piscis Austrinus", -37, -25, 21.4, 23.1], ["Microscopium", -45, -27, 20.4, 21.4], ["Telescopium", -57, -45, 18.1, 20.5], ["Corona Australis", -46, -37, 17.8, 19.3], ["Mensa", -85, -70, 3.2, 7.6], ["Volans", -75, -64, 6.6, 9.0], ["Chamaeleon", -83, -75, 7.5, 13.9], ["Octans", -90, -74, 0, 24], ["Vela", -57, -37, 8.0, 11.2], ["Hydra", -35, 7, 8.1, 15.0]];

var AstronomyFallback = (function(){
  function AstroTime(date){ this.date = date instanceof Date ? date : new Date(date); }
  function Observer(lat, lon, h){ this.latitude=lat; this.longitude=lon; this.height=h||0; }
  // GMST en horas (Meeus, aprox)
  function SiderealTime(t){
    var d = t.date.getTime()/86400000 + 2440587.5 - 2451545.0;
    var T = d/36525.0;
    var gmst = 280.46061837 + 360.98564736629*d
             + 0.000387933*T*T - (T*T*T)/38710000.0;
    gmst = ((gmst % 360)+360)%360;
    return gmst/15.0; // horas
  }
  // Resolvedor por cajas
  function Constellation(raHours, decDeg){
    var ra = ((raHours%24)+24)%24;
    var best=null, bestArea=1e9;
    for(var i=0;i<BOXES.length;i++){
      var b=BOXES[i]; // [name, decMin, decMax, raMin, raMax]
      var dmin=b[1], dmax=b[2], rmin=b[3], rmax=b[4];
      if(decDeg<dmin||decDeg>dmax) continue;
      var inRa;
      if(rmin<=rmax) inRa = (ra>=rmin && ra<rmax);
      else inRa = (ra>=rmin || ra<rmax); // cruza 0h
      if(!inRa) continue;
      var raSpan = (rmax-rmin+24)%24; if(raSpan===0) raSpan=24;
      var area=(dmax-dmin)*raSpan; // caja mas pequena gana (mas especifica)
      if(area<bestArea){bestArea=area; best=b[0];}
    }
    return { name: best || "Cielo abierto", symbol: best||"" };
  }
  return { AstroTime:AstroTime, Observer:Observer,
           SiderealTime:SiderealTime, Constellation:Constellation };
})();

window.AstronomyFallback = AstronomyFallback;
